sql:
SELECT AVG(age) AS avg_age
FROM individuals
WHERE indigeneity = 1 AND risky_alcohol = 1;

SELECT * FROM individuals
WHERE smoker = 1
AND risky_alcohol = 1;

SELECT individual_name, date_of_birth, contact_number, email
FROM individuals
WHERE smoker = 1;

external_knowledge:
- 'young adults' refers to the age group 21 to 30 years old;
- 'storm of vices' is a metaphor for engaging in harmful habits such as smoking and risky alcohol consumption;
- 'battling both smoke and alcohol' indicates individuals who are smokers and consume alcohol in a risky manner;
- 'existing health battles' refers to any health conditions they may have.

sql:
SELECT COUNT(*)
FROM individuals
WHERE sex = 1;

external_knowledge:
Troubled: individuals with psychological distress levels of 11 or higher;
Non-English speakers: those whose primary language is not English;
Countryside: refers to rural areas;
Indulge in smoking: refers to smoking status.

- 'torchbearers' metaphorically refers to the individuals in the database;
- 'flames' metaphorically refers to their smoking status (whether they are smokers or non-smokers);
- 'journey through life' adds a metaphorical context suggesting a lifelong characteristic.

sql:
SELECT COUNT(*) 
FROM individuals 
WHERE smoker = (SELECT smoking_id FROM smoking_types WHERE smoking_name = 'Smoker');

SELECT individual_name, sex, partnered, indigeneity, high_school, remoteness, language, smoker, risky_alcohol, psyc_distress
FROM individuals
WHERE sex = 1 AND partnered = 1 AND indigeneity = 1 AND high_school = 1 AND remoteness = 1 AND language = 0 AND smoker = 1 AND risky_alcohol = 1 AND psyc_distress > 50;

SELECT * 
FROM individuals
WHERE partnered = 1 AND high_school = 1;
